// Filtrar solo adjuntos PDF
const items = [];
const attachments = $input.first().json.attachments || [];

for (const att of attachments) {
  const filename = (att.filename || att.fileName || '').toLowerCase();
  const contentType = (att.contentType || att.mimeType || '').toLowerCase();

  if (filename.endsWith('.pdf') || contentType.includes('pdf')) {
    items.push({
      json: {
        ...($input.first().json),
        current_attachment: att,
        attachment_filename: att.filename || att.fileName,
        attachment_data: att.content || att.data,
      },
      binary: $input.first().binary
    });
  }
}

if (items.length === 0) {
  // Si no hay PDFs, pasar el item original para notificar
  items.push({
    json: {
      ...($input.first().json),
      no_pdf: true
    }
  });
}

return items;

